<template>
	<div class="wrapper">
		<div class="left-panel">
		<header>
			<div class="logo" />
		</header>
		<div class="create-account">
			<h2 class="create-account__headline">
				Create your GoPaperless account
			</h2>
			<p class="create-account__subtext">
				Securely sign and manage documents with GoPaperless.
			</p>
			<NcNoteCard type="info">
				{{ t('libresign', 'You need to create an account with the same email address you received the invitation from.') }}
			</NcNoteCard>
			<NcNoteCard v-if="errorMessage" type="error">
				{{ errorMessage }}
			</NcNoteCard>
			<fieldset class="create-account__fieldset">
				<NcTextField v-model="email"
					:label="t('libresign', 'Email')"
					autocapitalize="none"
					:spellchecking="false"
					autocomplete="off"
					:disabled="loading"
					:helper-text="emailError"
					:error="showErrorEmail"
					required>
					<NcIconSvgWrapper :path="mdiEmail" :size="20" />
				</NcTextField>
				<NcTextField
					v-model="phoneNumber"
					:label="t('libresign', 'Phone Number')"
					type="tel"
					placeholder="0712345678"
					:helper-text="phoneNumberError"
					:error="showErrorPhoneNumber"
					@blur="v$.phoneNumber.$touch()">
					<NcIconSvgWrapper :path="mdiPhone" :size="20" />
				</NcTextField>
				<NcPasswordField v-model="password"
					:label="t('libresign', 'Password')"
					:spellchecking="false"
					autocapitalize="none"
					autocomplete="off"
					:disabled="loading"
					:helper-text="passwordError"
					:error="passwordError.length > 0"
					@blur="v$.password.$touch()"
					required />
				<NcPasswordField v-model="passwordConfirm"
					:label="t('libresign', 'Confirm password')"
					:spellchecking="false"
					autocapitalize="none"
					autocomplete="off"
					:disabled="loading"
					:helper-text="confirmPasswordError"
					:error="confirmPasswordError.length > 0"
					@blur="v$.passwordConfirm.$touch()"
					required />
				<div class="login-button-container">
					<NcButton :wide="true"
						variant="primary"
						:disabled="!canSave"
						@click="createAccount">
						<template #icon>
							<NcLoadingIcon v-if="loading" :size="20" />
							<NcIconSvgWrapper v-else :path="mdiChevronRight" :size="20" />
						</template>
						{{ t('libresign', 'Next') }}
					</NcButton>
				</div>
			</fieldset>
		</div>
		</div>
		<div class="right-panel"></div>
	</div>
</template>

<script setup lang="ts">
import { t } from '@nextcloud/l10n'
import { computed, getCurrentInstance, onBeforeMount, reactive, ref, toRefs, type Ref } from 'vue'

import md5 from 'blueimp-md5'


import axios from '@nextcloud/axios'
import { showWarning } from '@nextcloud/dialogs'
import { loadState } from '@nextcloud/initial-state'
import { generateOcsUrl } from '@nextcloud/router'

import NcButton from '@nextcloud/vue/components/NcButton'
import NcLoadingIcon from '@nextcloud/vue/components/NcLoadingIcon'
import NcNoteCard from '@nextcloud/vue/components/NcNoteCard'
import NcPasswordField from '@nextcloud/vue/components/NcPasswordField'
import NcTextField from '@nextcloud/vue/components/NcTextField'
import NcIconSvgWrapper from '@nextcloud/vue/components/NcIconSvgWrapper'
import { sanitisePhoneNumber } from '../utils/phone'
import {
	mdiEmail,
	mdiChevronRight,
	mdiPhone,
} from '@mdi/js'

type CreateAccountSettings = {
	accountHash?: string
}

type RouteState = {
	params: {
		uuid?: string
	}
}

type RouterState = {
	resolve: (location: { name: string }) => { href: string }
}

type ValidationField<T extends string> = {
	$model: string
	$touch: () => Promise<void>
	$error: boolean
} & {
	[K in T]: {
		$invalid: boolean
	}
}

defineOptions({
	name: 'CreateAccount',
})

const instance = getCurrentInstance()
const route = computed<RouteState>(() => (instance?.proxy?.$route as RouteState | undefined) ?? { params: {} })
const router = computed<RouterState | undefined>(() => instance?.proxy?.$router as RouterState | undefined)

const state = reactive({
	loading: false,
	email: '',
	phoneNumber: '',
	password: '',
	passwordConfirm: '',
	settings: loadState<CreateAccountSettings>('libresign', 'settings', {}),
	message: loadState<string>('libresign', 'message', ''),
	errorMessage: '',
	enabledFeatures: [] as unknown[],
})

const {
	loading,
	email,
	phoneNumber,
	password,
	passwordConfirm,
	errorMessage,
} = toRefs(state)

const emailTouched = ref(false)
const phoneNumberTouched = ref(false)
const passwordTouched = ref(false)
const passwordConfirmTouched = ref(false)

const isRequired = (value: string) => value.length > 0
const isEmailValid = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)
const hasMinLength = (value: string, length: number) => value.length >= length

function createValidationField<T extends string>(
	source: Ref<string>,
	touched: Ref<boolean>,
	validators: Record<T, () => boolean>
): ValidationField<T> {
	const validatorEntries = validators as Record<string, () => boolean>

	const fields = Object.fromEntries(
    Object.keys(validatorEntries).map((key) => [
      key,
      {
        get $invalid() {
          return !validatorEntries[key]()
        },
      },
    ])
  ) as { [K in T]: { $invalid: boolean } }

	return {
		get $model() {
			return source.value
		},
		set $model(value: string) {
			source.value = value
		},
		async $touch() {
			touched.value = true
		},
		get $error() {
			return touched.value && Object.values(validatorEntries).some((v) => !v())
		},
		...fields,
	}
}

const v$ = {
	email: createValidationField(email, emailTouched, {
		required: () => isRequired(email.value),
		email: () => isEmailValid(email.value),
	}),
	phoneNumber: createValidationField(phoneNumber, phoneNumberTouched, {
		required: () => !!phoneNumber.value,
		phone: () => !!sanitisePhoneNumber(phoneNumber.value),
	}),
	password: createValidationField(password, passwordTouched, {
		required: () => isRequired(password.value),
		minLength: () => hasMinLength(password.value, 4),
	}),
	passwordConfirm: createValidationField(passwordConfirm, passwordConfirmTouched, {
		required: () => isRequired(passwordConfirm.value),
		minLength: () => hasMinLength(passwordConfirm.value, 4),
		sameAs: () => passwordConfirm.value === password.value,
	}),
}

const emailError = computed(() => {
	if (email.value) {
		if (v$.email.$error) {
			return t('libresign', 'This is not a valid email')
		}
		if (!isEqualEmail.value) {
			return t('libresign', 'The email entered is not the same as the email in the invitation')
		}
	}
	return ''
})

const showErrorEmail = computed(() => emailError.value.length > 0)

const phoneNumberError = computed(() => {
  if (!v$.phoneNumber.$error) return ''

  if (v$.phoneNumber.required.$invalid) {
    return 'Phone number is required'
  }
  if (v$.phoneNumber.phone.$invalid) {
    return 'Enter a valid phone number'
  }
  return ''
})

const showErrorPhoneNumber = computed(() => phoneNumberError.value.length > 0)

const passwordError = computed(() => {
    if (!v$.password.$error) return ''
    if (v$.password.required.$invalid) {
        return t('libresign', 'Password is required')
    }
    if (v$.password.minLength.$invalid) {
        return t('libresign', 'Your password must be greater than 3 digits')
    }
    return ''
})

const confirmPasswordError = computed(() => {
    if (!v$.passwordConfirm.$error) return ''
    if (v$.passwordConfirm.required.$invalid) {
        return t('libresign', 'Password confirmation is required')
    }
    if (v$.passwordConfirm.minLength.$invalid) {
        return t('libresign', 'Your password must be greater than 3 digits')
    }
	if (v$.passwordConfirm.sameAs.$invalid) {
		return t('libresign', 'Passwords do not match')
    }
    return ''
})

const isEqualEmail = computed(() => state.settings.accountHash === md5(email.value))

const canSave = computed(() => {
	return !v$.email.$error
		&& !v$.phoneNumber.$error
		&& !v$.password.$error
		&& !v$.passwordConfirm.$error
		&& state.email.length > 0
		&& state.password.length > 0
		&& state.passwordConfirm.length > 0
		&& !state.loading
})

onBeforeMount(() => {
	if (state.message) {
		showWarning(state.message)
	}
})

async function createAccount() {
	state.loading = true

	const normalizedPhone = sanitisePhoneNumber(state.phoneNumber)

	if (!normalizedPhone) {
		state.errorMessage = 'Invalid phone number'
		state.loading = false
		return
	}

	try {
		await axios.post(generateOcsUrl('/apps/libresign/api/v1/account/create/{uuid}'), {
			tuuid: route.value.params.uuid ?? '',
			email: state.email,
			phone: normalizedPhone,
			password: state.password,
		})
		if (!router.value) {
			return
		}
		const url = router.value.resolve({ name: 'SignPDFExternal' })
		window.location.href = url.href
	} catch (error: any) {
		state.errorMessage = error.response.data.ocs.data.message
	}
	state.loading = false
}

defineExpose({
	v$,
	email,
	password,
	passwordConfirm,
	loading,
	errorMessage,
	settings: state.settings,
	emailError,
	showErrorEmail,
	showErrorPhoneNumber,
	passwordError,
	confirmPasswordError,
	canSave,
	isEqualEmail,
	createAccount,
})
</script>

